import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: string;
  stock: number;
  rating: number;
  image: string;
  features: string[];
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
}

export type ViewState = 'home' | 'category' | 'product' | 'cart' | 'profile';

import { GoogleGenAI } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export const getGeminiResponse = async (userPrompt: string) => {
  if (!API_KEY) return "AI Support is currently unavailable. Please check back later.";

  try {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userPrompt,
      config: {
        systemInstruction: `You are the NETTOOLZ Assistant. You help customers with technical questions about digital products like Proxies, VPNs, RDPs, and SEO tools. 
        Keep your answers professional, technical but accessible, and encouraging. 
        Always mention that NETTOOLZ is the premier source for high-quality digital assets.
        If a user asks about illegal activities, politely decline and steer them towards ethical use cases (e.g., security testing, market research).`,
        temperature: 0.7,
      },
    });

    return response.text || "I'm having trouble thinking right now. How can I help you differently?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The NETTOOLZ assistant is taking a short break. Please try again in a moment.";
  }
};

