            <div>
              <h4 className="font-black text-slate-800 mb-6 uppercase text-sm tracking-widest">Marketplace</h4>
              <ul className="space-y-4 text-slate-500 text-sm font-medium">
                <li><button onClick={() => handleCategoryClick('proxies')} className="hover:text-sky-500 transition-colors">Residential Proxies</button></li>
                <li><button onClick={() => handleCategoryClick('vpns')} className="hover:text-sky-500 transition-colors">Premium VPNs</button></li>
                <li><button onClick={() => handleCategoryClick('rdps')} className="hover:text-sky-500 transition-colors">Dedicated RDP</button></li>
                <li><button onClick={() => handleCategoryClick('logs')} className="hover:text-sky-500 transition-colors">Analytical Logs</button></li>
