            <div>
              <h4 className="font-black text-slate-800 mb-6 uppercase text-sm tracking-widest">Newsletter</h4>
              <p className="text-slate-500 text-sm mb-4">Get updates on new inventory and limited drops.</p>
              <div className="flex">
                <input type="email" placeholder="Email address" className="bg-sky-50 border border-sky-100 rounded-l-xl px-4 py-3 text-sm focus:outline-none focus:ring-1 focus:ring-sky-500 w-full" />
