          </div>

          <div className="pt-8 border-t border-sky-100 flex flex-col md:flex-row justify-between items-center text-slate-400 text-xs font-bold">
            <p>© 2024 NETTOOLZ MARKETPLACE. ALL RIGHTS RESERVED.</p>
