import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser } from '../types';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [newAdminName, setNewAdminName] = useState('');

  const handleToggleVisibility = (id: string) => {
    const updated = products.map(p => p.id === id ? { ...p, isVisible: !p.isVisible } : p);
    onUpdateProducts(updated);
  };

  const handleDeleteProduct = (id: string) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSaveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (products.find(p => p.id === editingProduct.id)) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    } else {
      onUpdateProducts([...products, editingProduct]);
    }
    setEditingProduct(null);
  };

  const handleAddProduct = () => {
    setEditingProduct({
      id: Date.now().toString(),
      name: '',
      description: '',
      price: 0,
      category: CATEGORIES[0].id,
      stock: 0,
      rating: 5.0,
      image: 'https://picsum.photos/seed/new/400/300',
      features: [],
      isVisible: true
    });
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAdminName.trim()) return;
    const newAdmin: AdminUser = {
      id: Date.now().toString(),
      username: newAdminName,
      role: 'editor'
    };
    onUpdateAdmins([...admins, newAdmin]);
    setNewAdminName('');
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white rounded-3xl border border-sky-100 overflow-hidden shadow-xl mb-12">
      {/* Admin Sidebar */}
      <div className="w-full md:w-64 bg-slate-900 text-white p-8">
        <div className="flex items-center space-x-3 mb-10">
          <div className="bg-sky-500 p-2 rounded-lg"><i className="fa-solid fa-gauge-high"></i></div>
          <span className="text-xl font-black">Dashboard</span>
        </div>

        <nav className="space-y-4">
          <button 
            onClick={() => setActiveTab('products')}
            className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-all ${activeTab === 'products' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <i className="fa-solid fa-box-open"></i>
            <span>Products</span>
          </button>
          <button 
            onClick={() => setActiveTab('admins')}
            className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-all ${activeTab === 'admins' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <i className="fa-solid fa-users-gear"></i>
            <span>Admins</span>
          </button>
          <button 
            onClick={() => setActiveTab('settings')}
            className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-all ${activeTab === 'settings' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <i className="fa-solid fa-sliders"></i>
            <span>Settings</span>
          </button>
        </nav>

        <div className="mt-20 pt-10 border-t border-slate-800">
          <button 
            onClick={onLogout}
            className="w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 text-red-400 hover:bg-red-500/10 transition-all"
          >
            <i className="fa-solid fa-power-off"></i>
            <span>Logout</span>
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 p-8 bg-sky-50/30 overflow-x-auto">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-10 gap-4">
          <div>
            <h2 className="text-3xl font-black text-slate-800 capitalize">{activeTab} Management</h2>
            <p className="text-slate-500 font-medium">Manage your digital empire efficiently.</p>
          </div>
          {activeTab === 'products' && (
            <button 
              onClick={handleAddProduct}
              className="bg-sky-500 hover:bg-sky-600 text-white font-bold px-6 py-3 rounded-xl shadow-lg shadow-sky-200 transition-all flex items-center space-x-2"
            >
              <i className="fa-solid fa-plus"></i>
              <span>Add New Product</span>
            </button>
          )}
        </header>

        {/* Tab Content */}
        {activeTab === 'products' && (
          <div className="bg-white rounded-2xl border border-sky-100 overflow-hidden shadow-sm">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-sky-50/50 text-slate-400 text-xs font-black uppercase tracking-widest border-b border-sky-100">
                  <th className="px-6 py-4">Image</th>
                  <th className="px-6 py-4">Product Name</th>
                  <th className="px-6 py-4">Price</th>
                  <th className="px-6 py-4">Stock</th>
                  <th className="px-6 py-4">Visibility</th>
                  <th className="px-6 py-4">Actions</th>
                </tr>
              </thead>
              <tbody className="text-sm font-medium text-slate-600">
                {products.map(p => (
                  <tr key={p.id} className="border-b border-sky-50 hover:bg-sky-50/20 transition-colors">
                    <td className="px-6 py-4">
                      <img src={p.image} className="w-12 h-12 rounded-lg object-cover border border-sky-100" />
                    </td>
                    <td className="px-6 py-4 font-bold text-slate-800">{p.name}</td>
                    <td className="px-6 py-4">{settings.currencySymbol}{p.price.toFixed(2)}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-md ${p.stock < 10 ? 'bg-red-50 text-red-500' : 'bg-green-50 text-green-500'}`}>
                        {p.stock} units
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <button 
                        onClick={() => handleToggleVisibility(p.id)}
                        className={`w-12 h-6 rounded-full transition-all relative ${p.isVisible ? 'bg-sky-500' : 'bg-slate-300'}`}
                      >
                        <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${p.isVisible ? 'right-1' : 'left-1'}`}></div>
                      </button>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex space-x-3">
                        <button onClick={() => setEditingProduct(p)} className="text-sky-500 hover:bg-sky-50 p-2 rounded-lg transition-colors">
                          <i className="fa-solid fa-pen-to-square"></i>
                        </button>
                        <button onClick={() => handleDeleteProduct(p.id)} className="text-red-400 hover:bg-red-50 p-2 rounded-lg transition-colors">
                          <i className="fa-solid fa-trash"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {activeTab === 'admins' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-white p-8 rounded-2xl border border-sky-100 shadow-sm">
              <h3 className="text-xl font-black text-slate-800 mb-6">Current Administrators</h3>
              <div className="space-y-4">
                {admins.map(admin => (
                  <div key={admin.id} className="flex items-center justify-between p-4 bg-sky-50/50 rounded-xl border border-sky-50">
                    <div className="flex items-center space-x-4">
                      <div className="bg-sky-500 text-white w-10 h-10 rounded-full flex items-center justify-center font-bold">
                        {admin.username[0].toUpperCase()}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{admin.username}</p>
                        <p className="text-xs text-slate-400 uppercase font-black tracking-widest">{admin.role}</p>
                      </div>
                    </div>
                    {admin.username !== 'Admin' && (
                      <button 
                        onClick={() => onUpdateAdmins(admins.filter(a => a.id !== admin.id))}
                        className="text-red-400 hover:text-red-600"
                      >
                        <i className="fa-solid fa-user-minus"></i>
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white p-8 rounded-2xl border border-sky-100 shadow-sm">
              <h3 className="text-xl font-black text-slate-800 mb-6">Add New Administrator</h3>
              <form onSubmit={handleAddAdmin} className="space-y-4">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Username</label>
                  <input 
                    type="text" 
                    value={newAdminName}
                    onChange={(e) => setNewAdminName(e.target.value)}
                    placeholder="Enter username" 
                    className="w-full px-4 py-3 bg-sky-50 border border-sky-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-sky-500"
                  />
                </div>
                <button type="submit" className="w-full bg-sky-500 text-white font-bold py-3 rounded-xl hover:bg-sky-600 transition-colors shadow-lg shadow-sky-100">
