              <div className="pt-6 border-t border-sky-50">
                <button className="bg-sky-500 text-white font-bold px-8 py-3 rounded-xl hover:bg-sky-600 transition-all">
                  Save All Changes
                </button>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Product Edit Modal */}
      {editingProduct && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setEditingProduct(null)}></div>
          <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
