import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, Category, SiteSettings, AdminUser } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Admin & Settings State
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [admins, setAdmins] = useState<AdminUser[]>([
    { id: '1', username: 'Admin', role: 'super' }
  ]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'USD',
    currencySymbol: '$',
    storeName: 'NETTOOLZ'
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // Persistence (Simulated)
  useEffect(() => {
    const savedProducts = localStorage.getItem('nettoolz_products');
    if (savedProducts) setProducts(JSON.parse(savedProducts));

    const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
    if (savedAdmin === 'true') setIsAdminLoggedIn(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
  }, [products]);

  // Cart logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  // Navigation handlers
  const handleNavigate = (view: ViewState) => {
    if (view === 'admin_dashboard' && !isAdminLoggedIn) {
      setCurrentView('admin_login');
    } else {
      setCurrentView(view);
    }
    setSelectedProduct(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCategoryClick = (catId: string) => {
    setSelectedCategory(catId);
    setCurrentView('category');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView('product');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      localStorage.setItem('nettoolz_admin_logged', 'true');
      setCurrentView('admin_dashboard');
    }
  };

  const handleAdminLogout = () => {
    setIsAdminLoggedIn(false);
    localStorage.removeItem('nettoolz_admin_logged');
    setCurrentView('home');
  };

  // Filtered products (only visible ones for customers)
  const availableProducts = isAdminLoggedIn ? products : products.filter(p => p.isVisible);
  const filteredProducts = selectedCategory 
    ? availableProducts.filter(p => p.category === selectedCategory) 
    : availableProducts;

  // Views
  const renderHome = () => (
    <div className="space-y-16 py-12">
      {/* Hero Section */}
      <section className="relative px-6 py-20 bg-white rounded-3xl border border-sky-100 overflow-hidden">
        <div className="absolute top-0 right-0 -mr-20 -mt-20 w-96 h-96 bg-sky-100 rounded-full blur-3xl opacity-50"></div>
        <div className="absolute bottom-0 left-0 -ml-20 -mb-20 w-96 h-96 bg-sky-200 rounded-full blur-3xl opacity-30"></div>

        <div className="relative z-10 text-center max-w-3xl mx-auto">
          <span className="inline-block px-4 py-2 bg-sky-100 text-sky-600 rounded-full text-xs font-black uppercase tracking-widest mb-6">
            Global Digital Distribution
          </span>
          <h1 className="text-5xl sm:text-6xl font-black text-slate-900 leading-tight mb-6">
            Empower Your Tech <br/> With <span className="text-sky-500 underline decoration-sky-200 underline-offset-8">Premium Tools</span>
          </h1>
          <p className="text-lg text-slate-500 mb-10 leading-relaxed">
            The #1 marketplace for high-performance proxies, VPNs, RDPs, and traffic logs. 
            Trusted by developers and data scientists worldwide.
          </p>
          <div className="flex flex-col sm:flex-row items-center justify-center space-y-4 sm:space-y-0 sm:space-x-4">
            <button 
              onClick={() => handleNavigate('category')}
              className="w-full sm:w-auto bg-sky-500 hover:bg-sky-600 text-white font-bold px-10 py-4 rounded-2xl shadow-xl shadow-sky-200 transition-all hover:-translate-y-1 active:scale-95"
            >
              Browse Marketplace
            </button>
            <button className="w-full sm:w-auto bg-white border-2 border-sky-100 text-sky-500 font-bold px-10 py-4 rounded-2xl hover:bg-sky-50 transition-all">
              Learn More
            </button>
          </div>
        </div>
      </section>

      {/* Featured Products */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-3xl font-black text-slate-800">Top Rated Tools</h2>
          <button onClick={() => setCurrentView('category')} className="text-sky-500 font-bold hover:underline">View All</button>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {availableProducts.slice(0, 3).map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onAddToCart={addToCart} 
              onViewDetails={handleProductClick}
            />
          ))}
        </div>
      </section>
    </div>
  );

  const renderCategory = () => (
    <div className="py-12">
      <div className="flex flex-col md:flex-row gap-12">
        {/* Sidebar */}
        <div className="w-full md:w-64 space-y-8">
          <div>
            <h3 className="text-lg font-black text-slate-800 mb-4">Categories</h3>
            <div className="space-y-2">
              <button 
                onClick={() => setSelectedCategory(null)}
                className={`w-full text-left px-4 py-2 rounded-xl transition-all ${!selectedCategory ? 'bg-sky-500 text-white font-bold' : 'bg-white border border-sky-100 text-slate-600 hover:bg-sky-50'}`}
              >
                All Tools
              </button>
              {CATEGORIES.map(cat => (
                <button 
                  key={cat.id}
                  onClick={() => setSelectedCategory(cat.id)}
                  className={`w-full text-left px-4 py-2 rounded-xl transition-all ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold' : 'bg-white border border-sky-100 text-slate-600 hover:bg-sky-50'}`}
                >
                  {cat.name}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-3xl font-black text-slate-800">
              {selectedCategory ? CATEGORIES.find(c => c.id === selectedCategory)?.name : 'All Tools'}
              <span className="ml-4 text-sm font-bold text-slate-400">{filteredProducts.length} results</span>
            </h2>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredProducts.map(p => (
              <ProductCard 
                key={p.id} 
                product={p} 
                onAddToCart={addToCart} 
                onViewDetails={handleProductClick}
              />
            ))}
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        cartCount={cartItemCount} 
        onNavigate={handleNavigate} 
        onOpenCart={() => setIsCartOpen(true)} 
      />

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && renderHome()}
        {currentView === 'category' && renderCategory()}
        {currentView === 'product' && selectedProduct && (
          <div className="py-12">
             <button onClick={() => setCurrentView('category')} className="mb-8 flex items-center text-sky-500 font-bold hover:text-sky-600">
                <i className="fa-solid fa-arrow-left mr-2"></i> Back to Store
              </button>
              <div className="bg-white rounded-3xl border border-sky-100 p-8 flex flex-col lg:flex-row gap-12">
                <div className="flex-1"><img src={selectedProduct.image} className="w-full h-auto rounded-2xl" /></div>
                <div className="flex-1 space-y-6">
                   <h1 className="text-4xl font-black">{selectedProduct.name}</h1>
                   <p className="text-4xl font-black text-sky-500">{settings.currencySymbol}{selectedProduct.price.toFixed(2)}</p>
                   <p className="text-slate-500 leading-relaxed">{selectedProduct.description}</p>
                   <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-bold py-4 rounded-xl">Add to Cart</button>
                </div>
              </div>
          </div>
        )}
        {currentView === 'admin_login' && <AdminLogin onLogin={handleAdminLogin} onCancel={() => handleNavigate('home')} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && (
          <AdminDashboard 
            products={products} 
            settings={settings}
            admins={admins}
            onUpdateProducts={setProducts}
            onUpdateSettings={setSettings}
            onUpdateAdmins={setAdmins}
            onLogout={handleAdminLogout}
          />
        )}
      </main>

      {/* Cart Drawer & Gemini Assistant... (remains largely same as before but uses settings.currencySymbol) */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] overflow-hidden">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute right-0 top-0 bottom-0 w-full max-w-md bg-white shadow-2xl animate-in slide-in-from-right duration-300 flex flex-col p-6">
            <h2 className="text-2xl font-black mb-6">Your Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50/30 rounded-xl border border-sky-50">
                  <img src={item.image} className="w-16 h-16 rounded-lg object-cover" />
                  <div className="flex-1">
                    <p className="font-bold text-slate-800">{item.name}</p>
                    <p className="text-sm font-bold text-sky-500">{settings.currencySymbol}{item.price.toFixed(2)} x {item.quantity}</p>
                  </div>
                  <button onClick={() => removeFromCart(item.id)} className="text-red-400"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
            </div>
            <div className="pt-6 border-t border-sky-100 mt-6">
              <div className="flex justify-between items-center text-xl font-black mb-4">
                <span>Total</span>
                <span className="text-sky-500">{settings.currencySymbol}{totalCartPrice.toFixed(2)}</span>
              </div>
              <button className="w-full bg-sky-500 text-white font-black py-4 rounded-xl">Checkout</button>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="bg-white border-t border-sky-100 mt-20 py-8">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-slate-400 text-xs font-bold">© 2024 {settings.storeName}. ALL RIGHTS RESERVED.</p>
          <button 
            onClick={() => handleNavigate('admin_dashboard')}
            className="mt-4 text-slate-300 hover:text-sky-400 transition-colors text-[10px] font-black uppercase tracking-[0.2em]"
          >
            Terminal Access
          </button>
        </div>
      </footer>

      <GeminiAssistant />
    </div>
  );
};

export default App;

