import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [newAdminName, setNewAdminName] = useState('');

  const handleToggleVisibility = (id: string) => {
    const updated = products.map(p => p.id === id ? { ...p, isVisible: !p.isVisible } : p);
    onUpdateProducts(updated);
  };

  const handleDeleteProduct = (id: string) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSaveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (products.find(p => p.id === editingProduct.id)) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    } else {
      onUpdateProducts([...products, editingProduct]);
    }
    setEditingProduct(null);
  };

  const handleAddProduct = () => {
    setEditingProduct({
      id: Date.now().toString(),
      name: '',
      description: '',
      price: 0,
      category: CATEGORIES[0].id,
      stock: 0,
      rating: 5.0,
      image: 'https://picsum.photos/seed/new/400/300',
      features: [],
      isVisible: true,
      secretContent: ''
    });
  };

  const updatePaymentMethod = (id: string, updates: Partial<PaymentMethod>) => {
    const newMethods = settings.paymentMethods.map(m => m.id === id ? { ...m, ...updates } : m);
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
  };

  const handleAddAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAdminName.trim()) return;
    const newAdmin: AdminUser = {
      id: Date.now().toString(),
      username: newAdminName,
      role: 'editor'
    };
    onUpdateAdmins([...admins, newAdmin]);
    setNewAdminName('');
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white rounded-3xl border border-sky-100 overflow-hidden shadow-xl mb-12">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8">
        <div className="flex items-center space-x-3 mb-10">
          <div className="bg-sky-500 p-2 rounded-lg"><i className="fa-solid fa-gauge-high"></i></div>
          <span className="text-xl font-black">Admin Panel</span>
        </div>

        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'products' ? 'bg-sky-500' : 'text-slate-400'}`}>
            <i className="fa-solid fa-box-open w-5"></i><span>Products</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'payments' ? 'bg-sky-500' : 'text-slate-400'}`}>
            <i className="fa-solid fa-credit-card w-5"></i><span>Payments</span>
          </button>
          <button onClick={() => setActiveTab('admins')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'admins' ? 'bg-sky-500' : 'text-slate-400'}`}>
