import React, { useState } from 'react';
import { User } from '../types';

interface UserAuthProps {
  users: User[];
  onAuth: (user: User) => void;
  onCancel: () => void;
}

const UserAuth: React.FC<UserAuthProps> = ({ users, onAuth, onCancel }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (isLogin) {
      const user = users.find(u => u.email === email && u.password === password);
      if (user) {
        onAuth(user);
      } else {
        setError('Invalid email or password.');
      }
    } else {
      if (users.find(u => u.email === email)) {
        setError('Email already registered.');
        return;
      }
      const newUser: User = {
        id: Date.now().toString(),
        email,
        password,
        balance: 0,
        orders: []
      };
      onAuth(newUser);
    }
  };

  return (
    <div className="max-w-md mx-auto my-20 p-8 bg-white rounded-3xl border border-sky-100 shadow-xl">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-black text-slate-800">{isLogin ? 'Customer Login' : 'Create Account'}</h2>
        <p className="text-slate-500 mt-2">Access your NETTOOLZ portal</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Email</label>
          <input 
            type="email" 
            required 
            value={email}
            onChange={e => setEmail(e.target.value)}
            className="w-full px-4 py-3 bg-sky-50 border border-sky-100 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none"
            placeholder="name@example.com"
          />
        </div>
        <div>
          <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Password</label>
          <input 
            type="password" 
            required 
            value={password}
            onChange={e => setPassword(e.target.value)}
            className="w-full px-4 py-3 bg-sky-50 border border-sky-100 rounded-xl focus:ring-2 focus:ring-sky-500 outline-none"
            placeholder="••••••••"
          />
        </div>

        {error && <p className="text-red-500 text-sm font-bold text-center">{error}</p>}

        <button type="submit" className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg hover:bg-sky-600 transition-all">
          {isLogin ? 'Login' : 'Sign Up'}
        </button>

        <div className="flex items-center justify-between text-sm mt-6">
          <button type="button" onClick={() => setIsLogin(!isLogin)} className="text-sky-500 font-bold hover:underline">
            {isLogin ? "Don't have an account? Sign up" : "Already have an account? Login"}
          </button>
          <button type="button" onClick={onCancel} className="text-slate-400 font-bold">Cancel</button>
        </div>
      </form>
    </div>
  );
};

export default UserAuth;

