import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, Category, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Admin & Settings State
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [admins, setAdmins] = useState<AdminUser[]>([
    { id: '1', username: 'Admin', role: 'super' }
  ]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'USD',
    currencySymbol: '$',
    storeName: 'NETTOOLZ',
    paymentMethods: [
      { id: 'bank1', type: 'bank', name: 'Bank Transfer (KoralPay)', details: 'Bank: Global Trust Bank\nAccount: 0123456789\nName: NETTOOLZ ENTERPRISE', isActive: true },
      { id: 'crypto1', type: 'crypto', name: 'Crypto (USDT/BTC)', details: 'USDT (TRC20): T99xxxxxx...\nBTC: 1A2B3C...', isActive: true }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // User State
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Persistence
  useEffect(() => {
    const savedProducts = localStorage.getItem('nettoolz_products');
    if (savedProducts) setProducts(JSON.parse(savedProducts));

    const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
    if (savedAdmin === 'true') setIsAdminLoggedIn(true);

    const savedUsers = localStorage.getItem('nettoolz_users');
    if (savedUsers) setUsers(JSON.parse(savedUsers));

    const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
    if (loggedUserEmail && savedUsers) {
      const found = JSON.parse(savedUsers).find((u: User) => u.email === loggedUserEmail);
      if (found) setCurrentUser(found);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
    localStorage.setItem('nettoolz_users', JSON.stringify(users));
    if (currentUser) {
      localStorage.setItem('nettoolz_logged_user_email', currentUser.email);
    } else {
      localStorage.removeItem('nettoolz_logged_user_email');
    }
  }, [products, users, currentUser]);

  // Cart logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  // Checkout Logic
  const handleCheckout = () => {
    if (!currentUser) {
      setCurrentView('user_auth');
      setIsCartOpen(false);
      return;
    }

    if (currentUser.balance < totalCartPrice) {
      alert('Insufficient balance. Please fund your wallet.');
      setCurrentView('fund_wallet');
      setIsCartOpen(false);
      return;
    }

    const newOrders: UserOrder[] = cart.map(item => ({
      id: Date.now().toString() + Math.random(),
      productId: item.id,
      productName: item.name,
      content: item.secretContent || 'Login credentials pending verification.',
      price: item.price,
      timestamp: Date.now()
    }));

    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance - totalCartPrice,
      orders: [...currentUser.orders, ...newOrders]
    };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    setCart([]);
    setIsCartOpen(false);
    setCurrentView('profile');
    alert('Purchase successful! Product logins have been added to your profile.');
  };

  // Navigation handlers
  const handleNavigate = (view: ViewState) => {
    if (view === 'profile' && !currentUser) {
      setCurrentView('user_auth');
    } else if (view === 'admin_dashboard' && !isAdminLoggedIn) {
      setCurrentView('admin_login');
    } else {
      setCurrentView(view);
    }
    setSelectedProduct(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAuth = (user: User) => {
    const existing = users.find(u => u.email === user.email);
    if (!existing) {
      setUsers([...users, user]);
    }
    setCurrentUser(user);
    setCurrentView('profile');
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      localStorage.setItem('nettoolz_admin_logged', 'true');
      setCurrentView('admin_dashboard');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('home');
  };

  const handleAdminLogout = () => {
    setIsAdminLoggedIn(false);
    localStorage.removeItem('nettoolz_admin_logged');
    setCurrentView('home');
  };

  const availableProducts = products.filter(p => p.isVisible);
  const filteredProducts = selectedCategory 
    ? availableProducts.filter(p => p.category === selectedCategory) 
    : availableProducts;

