    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Bank Transfer)', 
        details: 'Transfer to the account below and send proof.', 
        bankName: 'Global Trust Bank',
        accountNumber: '0123456789',
        accountName: 'NETTOOLZ ENTERPRISE',
        isActive: true 
