  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
    localStorage.setItem('nettoolz_users', JSON.stringify(users));
    localStorage.setItem('nettoolz_settings', JSON.stringify(settings));
    if (currentUser) {
      localStorage.setItem('nettoolz_logged_user_email', currentUser.email);
    } else {
      localStorage.removeItem('nettoolz_logged_user_email');
    }
  }, [products, users, currentUser, settings]);

  // Cart logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  // Checkout Logic
  const handleCheckout = () => {
    if (!currentUser) {
      setCurrentView('user_auth');
      setIsCartOpen(false);
      return;
    }

    if (currentUser.balance < totalCartPrice) {
      alert(`Insufficient balance. Your balance: ${settings.currencySymbol}${currentUser.balance.toFixed(2)}. Required: ${settings.currencySymbol}${totalCartPrice.toFixed(2)}`);
      setCurrentView('fund_wallet');
      setIsCartOpen(false);
      return;
    }

    const newOrders: UserOrder[] = cart.map(item => ({
      id: Date.now().toString() + Math.random(),
      productId: item.id,
      productName: item.name,
      content: item.secretContent || 'Login credentials pending verification.',
      price: item.price,
      timestamp: Date.now()
    }));

    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance - totalCartPrice,
      orders: [...currentUser.orders, ...newOrders]
    };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    setCart([]);
    setIsCartOpen(false);
    setCurrentView('profile');
    alert('Purchase successful! Check your profile for product logins.');
  };

  // Navigation handlers
  const handleNavigate = (view: ViewState) => {
    if (view === 'profile' && !currentUser) {
      setCurrentView('user_auth');
    } else if (view === 'admin_dashboard' && !isAdminLoggedIn) {
      setCurrentView('admin_login');
    } else {
      setCurrentView(view);
    }
    setSelectedProduct(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAuth = (user: User) => {
    const existing = users.find(u => u.email === user.email);
    if (!existing) {
      setUsers([...users, user]);
    }
    setCurrentUser(user);
    setCurrentView('profile');
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      localStorage.setItem('nettoolz_admin_logged', 'true');
      setCurrentView('admin_dashboard');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('home');
  };

  const handleAdminLogout = () => {
    setIsAdminLoggedIn(false);
    localStorage.removeItem('nettoolz_admin_logged');
    setCurrentView('home');
  };

  const availableProducts = products.filter(p => p.isVisible);
  const filteredProducts = selectedCategory 
    ? availableProducts.filter(p => p.category === selectedCategory) 
    : availableProducts;

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        cartCount={cartItemCount} 
        onNavigate={handleNavigate} 
        onOpenCart={() => setIsCartOpen(true)} 
      />

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && (
          <div className="space-y-16 py-12">
            <section className="relative px-6 py-20 bg-white rounded-3xl border border-sky-100 overflow-hidden">
              <div className="absolute top-0 right-0 -mr-20 -mt-20 w-96 h-96 bg-sky-100 rounded-full blur-3xl opacity-50"></div>
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-2 bg-sky-100 text-sky-600 rounded-full text-xs font-black uppercase tracking-widest mb-6">Premium Digital Tools</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 leading-tight mb-6">Empower Your Tech With <span className="text-sky-500">Premium Tools</span></h1>
                <p className="text-lg text-slate-500 mb-10 leading-relaxed">The #1 marketplace for high-performance proxies, VPNs, and traffic logs in Nigeria.</p>
                <button onClick={() => setCurrentView('category')} className="bg-sky-500 hover:bg-sky-600 text-white font-bold px-10 py-4 rounded-2xl shadow-xl transition-all">Browse Marketplace</button>
              </div>
            </section>
            <section>
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-3xl font-black text-slate-800">Top Rated Tools</h2>
                <button onClick={() => setCurrentView('category')} className="text-sky-500 font-bold hover:underline">View All</button>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                {availableProducts.slice(0, 3).map(p => (
                  <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                ))}
              </div>
            </section>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12">
            <div className="flex flex-col md:flex-row gap-12">
              <div className="w-full md:w-64 space-y-4">
                <h3 className="text-lg font-black text-slate-800">Categories</h3>
                {CATEGORIES.map(cat => (
                  <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${selectedCategory === cat.id ? 'bg-sky-500 text-white' : 'hover:bg-sky-100'}`}>{cat.name}</button>
                ))}
                <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${!selectedCategory ? 'bg-sky-500 text-white' : 'hover:bg-sky-100'}`}>All Products</button>
              </div>
              <div className="flex-1">
                <h2 className="text-3xl font-black mb-8">{selectedCategory ? CATEGORIES.find(c => c.id === selectedCategory)?.name : 'All Products'}</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {filteredProducts.map(p => (
                    <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <button onClick={() => setCurrentView('category')} className="mb-8 font-bold text-sky-500"><i className="fa-solid fa-arrow-left mr-2"></i>Back</button>
            <div className="bg-white rounded-3xl p-8 border border-sky-100 flex flex-col md:flex-row gap-12">
              <div className="flex-1"><img src={selectedProduct.image} className="w-full h-auto rounded-2xl shadow-xl" /></div>
              <div className="flex-1 space-y-6">
                <h1 className="text-4xl font-black">{selectedProduct.name}</h1>
                <p className="text-3xl font-black text-sky-500">{settings.currencySymbol}{selectedProduct.price.toLocaleString()}</p>
                <p className="text-slate-500">{selectedProduct.description}</p>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg">Add to Cart</button>
