            </div>
          </div>
        )}

        {currentView === 'user_auth' && <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />}
        {currentView === 'profile' && currentUser && <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={handleLogout} />}
        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={handleAdminLogin} onCancel={() => handleNavigate('home')} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && (
          <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={setProducts} onUpdateSettings={setSettings} onUpdateAdmins={setAdmins} onLogout={handleAdminLogout} />
        )}
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl p-8 flex flex-col">
            <h2 className="text-2xl font-black mb-8">Shopping Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50/50 rounded-xl">
                  <img src={item.image} className="w-16 h-16 rounded-lg object-cover" />
                  <div className="flex-1">
                    <p className="font-bold">{item.name}</p>
                    <p className="text-sky-500 font-bold">{settings.currencySymbol}{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => removeFromCart(item.id)} className="text-red-400"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
              {cart.length === 0 && <p className="text-center text-slate-400 mt-20">Your cart is empty.</p>}
            </div>
            <div className="pt-8 border-t">
              <div className="flex justify-between text-2xl font-black mb-6">
                <span>Total</span>
                <span className="text-sky-500">{settings.currencySymbol}{totalCartPrice.toLocaleString()}</span>
              </div>
              <button onClick={handleCheckout} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg">Checkout with Wallet</button>
              {currentUser && <p className="text-center text-xs mt-4 text-slate-400 font-bold">Your Wallet: {settings.currencySymbol}{currentUser.balance.toLocaleString()}</p>}
