          </button>
          <button onClick={() => setActiveTab('admins')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'admins' ? 'bg-sky-500' : 'text-slate-400'}`}>
