import React, { useState, useRef, useEffect } from 'react';
import { getGeminiResponse } from '../services/geminiService';

const GeminiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([
    { role: 'ai', text: 'Welcome to NETTOOLZ! How can I help you find the right digital tools today?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    const response = await getGeminiResponse(userMsg);
    setMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsTyping(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100]">
      {/* Launcher */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-sky-500 hover:bg-sky-600 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center transition-all hover:scale-110 active:scale-90"
        >
          <i className="fa-solid fa-robot text-2xl"></i>
        </button>
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className="bg-white dark:bg-slate-900 w-[350px] sm:w-[400px] h-[500px] rounded-2xl shadow-2xl border border-sky-100 dark:border-slate-800 flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
          {/* Header */}
          <div className="bg-sky-500 p-4 flex justify-between items-center text-white">
            <div className="flex items-center space-x-3">
              <div className="bg-white/20 p-2 rounded-lg">
                <i className="fa-solid fa-robot"></i>
              </div>
              <div>
                <h4 className="font-bold">NETTOOLZ Assistant</h4>
                <p className="text-[10px] text-sky-100 uppercase tracking-widest font-bold">Powered by Gemini</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-2 rounded-lg transition-colors">
              <i className="fa-solid fa-xmark"></i>
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-sky-50/30 dark:bg-slate-950/30">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                  msg.role === 'user' 
                    ? 'bg-sky-500 text-white rounded-br-none' 
                    : 'bg-white dark:bg-slate-800 border border-sky-100 dark:border-slate-700 text-slate-800 dark:text-slate-100 rounded-bl-none shadow-sm'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-slate-800 border border-sky-100 dark:border-slate-700 p-3 rounded-2xl rounded-bl-none shadow-sm space-x-1 flex">
                  <div className="w-1.5 h-1.5 bg-sky-300 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-sky-300 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-sky-300 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 border-t border-sky-100 dark:border-slate-800 bg-white dark:bg-slate-900">
            <div className="flex space-x-2">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask anything about our tools..."
                className="flex-1 bg-sky-50 dark:bg-slate-800 border border-sky-100 dark:border-slate-700 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-sky-500 text-slate-900 dark:text-slate-100 placeholder-slate-400"
              />
              <button 
                onClick={handleSend}
                disabled={isTyping}
                className="bg-sky-500 hover:bg-sky-600 disabled:bg-sky-300 text-white p-2 rounded-xl transition-colors"
              >
                <i className="fa-solid fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GeminiAssistant;

import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [newAdminName, setNewAdminName] = useState('');

  const handleToggleVisibility = (id: string) => {
    const updated = products.map(p => p.id === id ? { ...p, isVisible: !p.isVisible } : p);
    onUpdateProducts(updated);
  };

  const handleDeleteProduct = (id: string) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      onUpdateProducts(products.filter(p => p.id !== id));
    }
  };

  const handleSaveProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;

    if (products.find(p => p.id === editingProduct.id)) {
      onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    } else {
      onUpdateProducts([...products, editingProduct]);
    }
    setEditingProduct(null);
  };

  const handleAddProduct = () => {
    setEditingProduct({
      id: Date.now().toString(),
      name: '',
      description: '',
      price: 0,
      category: CATEGORIES[0].id,
      stock: 0,
      rating: 5.0,
      image: 'https://picsum.photos/seed/new/400/300',
      features: [],
      isVisible: true,
      secretContent: ''
    });
  };

  // Payment Management Logic
  const handleAddPayment = () => {
    setEditingPayment({
      id: Date.now().toString(),
      type: 'bank',
      name: 'New Payment Method',
      details: 'Follow steps to pay...',
      isActive: true,
      bankName: '',
      accountNumber: '',
      accountName: '',
      walletAddress: '',
      network: ''
    });
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;

    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
  };

  const handleDeletePayment = (id: string) => {
    if (window.confirm('Delete this payment method?')) {
      const newMethods = settings.paymentMethods.filter(m => m.id !== id);
      onUpdateSettings({ ...settings, paymentMethods: newMethods });
    }
  };

  const updatePaymentMethodStatus = (id: string, active: boolean) => {
