          <button onClick={() => handleNavigate('admin_dashboard')} className="mt-8 text-[10px] text-slate-300 dark:text-slate-700 font-black uppercase tracking-[0.2em] hover:text-sky-500 transition-colors">Terminal Access</button>
        </div>
      </footer>

      <GeminiAssistant />
    </div>
  );
};

