    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Bank Transfer)', 
        details: 'Transfer to the account below and send proof.', 
        bankName: 'Global Trust Bank',
        accountNumber: '0123456789',
        accountName: 'NETTOOLZ ENTERPRISE',
        isActive: true,
        isAutomated: false
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (USDT/BTC)', 
        details: 'Send crypto and notify support for NGN balance credit.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: false
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // User State
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Theme Logic
  useEffect(() => {
    const savedTheme = localStorage.getItem('nettoolz_theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const shouldBeDark = savedTheme === 'dark' || (!savedTheme && prefersDark);
    setIsDarkMode(shouldBeDark);
    if (shouldBeDark) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, []);

  const toggleTheme = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    if (newMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('nettoolz_theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('nettoolz_theme', 'light');
    }
  };

  // Persistence
  useEffect(() => {
    const savedProducts = localStorage.getItem('nettoolz_products');
    if (savedProducts) setProducts(JSON.parse(savedProducts));

    const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
    if (savedAdmin === 'true') setIsAdminLoggedIn(true);

    const savedUsers = localStorage.getItem('nettoolz_users');
    if (savedUsers) setUsers(JSON.parse(savedUsers));

    const savedSettings = localStorage.getItem('nettoolz_settings');
    if (savedSettings) setSettings(JSON.parse(savedSettings));

    const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
    if (loggedUserEmail && savedUsers) {
      const found = JSON.parse(savedUsers).find((u: User) => u.email === loggedUserEmail);
      if (found) setCurrentUser(found);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
    localStorage.setItem('nettoolz_users', JSON.stringify(users));
    localStorage.setItem('nettoolz_settings', JSON.stringify(settings));
    if (currentUser) {
      localStorage.setItem('nettoolz_logged_user_email', currentUser.email);
    } else {
      localStorage.removeItem('nettoolz_logged_user_email');
    }
  }, [products, users, currentUser, settings]);

  // Cart logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  // Checkout Logic
  const handleCheckout = async () => {
    if (!currentUser) {
      setCurrentView('user_auth');
      setIsCartOpen(false);
      return;
    }

    if (currentUser.balance < totalCartPrice) {
      alert(`Insufficient balance. Required: ${settings.currencySymbol}${totalCartPrice.toLocaleString()}`);
      setCurrentView('fund_wallet');
      setIsCartOpen(false);
      return;
    }

    setIsProcessingCheckout(true);
    // Simulate a brief delay for "API validation" even for internal wallet checks
    await new Promise(resolve => setTimeout(resolve, 1500));

    const newOrders: UserOrder[] = cart.map(item => ({
      id: Date.now().toString() + Math.random(),
      productId: item.id,
      productName: item.name,
      content: item.secretContent || 'Processing credentials...',
      price: item.price,
      timestamp: Date.now()
    }));

    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance - totalCartPrice,
      orders: [...currentUser.orders, ...newOrders]
    };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    setCart([]);
    setIsCartOpen(false);
    setIsProcessingCheckout(false);
    setCurrentView('profile');
    alert('Purchase confirmed! Credentials have been sent to your profile.');
  };

  const handleNavigate = (view: ViewState) => {
    if (view === 'profile' && !currentUser) {
      setCurrentView('user_auth');
    } else if (view === 'admin_dashboard' && !isAdminLoggedIn) {
      setCurrentView('admin_login');
    } else {
      setCurrentView(view);
    }
    setSelectedProduct(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleAuth = (user: User) => {
    const existing = users.find(u => u.email === user.email);
    if (!existing) {
      setUsers([...users, user]);
    }
    setCurrentUser(user);
    setCurrentView('profile');
  };

  const handleAdminLogin = (success: boolean) => {
    if (success) {
      setIsAdminLoggedIn(true);
      localStorage.setItem('nettoolz_admin_logged', 'true');
      setCurrentView('admin_dashboard');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setCurrentView('home');
  };

  const handleAdminLogout = () => {
    setIsAdminLoggedIn(false);
    localStorage.removeItem('nettoolz_admin_logged');
    setCurrentView('home');
  };

  const availableProducts = products.filter(p => p.isVisible);
  const filteredProducts = selectedCategory 
    ? availableProducts.filter(p => p.category === selectedCategory) 
    : availableProducts;

  return (
    <div className="min-h-screen flex flex-col bg-sky-50 dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cartItemCount} 
        isDarkMode={isDarkMode}
        onNavigate={handleNavigate} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={toggleTheme}
      />

      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && (
          <div className="space-y-16 py-12">
            <section className="relative px-6 py-20 bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-sm transition-colors">
              <div className="absolute top-0 right-0 -mr-20 -mt-20 w-96 h-96 bg-sky-100 dark:bg-sky-900/10 rounded-full blur-3xl opacity-50"></div>
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-2 bg-sky-100 dark:bg-sky-900/30 text-sky-600 dark:text-sky-400 rounded-full text-xs font-black uppercase tracking-widest mb-6">Premium Digital Marketplace</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-tight mb-6 transition-colors">Digital Tools for <span className="text-sky-500">Power Users</span></h1>
                <p className="text-lg text-slate-500 dark:text-slate-400 mb-10 leading-relaxed transition-colors">Proxies, VPNs, and verified technical logs. Safe, fast, and professional.</p>
                <button onClick={() => setCurrentView('category')} className="bg-sky-500 hover:bg-sky-600 text-white font-bold px-10 py-4 rounded-2xl shadow-xl transition-all active:scale-95">Enter Store</button>
              </div>
            </section>

            <section>
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-3xl font-black text-slate-800 dark:text-slate-100">Featured Products</h2>
                <button onClick={() => setCurrentView('category')} className="text-sky-500 font-bold hover:underline">View All</button>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                {availableProducts.slice(0, 3).map(p => (
                  <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                ))}
              </div>
            </section>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12">
            <div className="flex flex-col md:flex-row gap-12">
              <div className="w-full md:w-64 space-y-4">
                <h3 className="text-lg font-black text-slate-800 dark:text-slate-100">Tools Directory</h3>
                <div className="space-y-2">
                  <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${!selectedCategory ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 border border-sky-100 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>All Assets</button>
                  {CATEGORIES.map(cat => (
                    <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 border border-sky-100 dark:border-slate-800 text-slate-600 dark:text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>{cat.name}</button>
                  ))}
                </div>
              </div>
              <div className="flex-1">
                <h2 className="text-3xl font-black mb-8 dark:text-white">{selectedCategory ? CATEGORIES.find(c => c.id === selectedCategory)?.name : 'All Products'}</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {filteredProducts.map(p => (
                    <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <button onClick={() => setCurrentView('category')} className="mb-8 font-bold text-sky-500 flex items-center hover:underline"><i className="fa-solid fa-arrow-left mr-2"></i>Back to Catalog</button>
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-sky-100 dark:border-slate-800 flex flex-col md:flex-row gap-12 shadow-sm transition-colors">
              <div className="flex-1 overflow-hidden rounded-2xl shadow-lg border border-sky-50 dark:border-slate-800">
                <img src={selectedProduct.image} className="w-full h-auto object-cover hover:scale-105 transition-transform" />
              </div>
              <div className="flex-1 space-y-6">
                <div>
                  <span className="text-sky-500 text-sm font-black uppercase tracking-widest">{selectedProduct.category}</span>
                  <h1 className="text-4xl font-black dark:text-white mt-2">{selectedProduct.name}</h1>
                </div>
                <p className="text-3xl font-black text-sky-500">₦{selectedProduct.price.toLocaleString()}</p>
                <p className="text-slate-500 dark:text-slate-400 leading-relaxed">{selectedProduct.description}</p>
                <div className="space-y-3">
                   {selectedProduct.features.map((f, i) => (
                     <div key={i} className="flex items-center space-x-2 text-sm font-semibold text-slate-600 dark:text-slate-400">
                        <i className="fa-solid fa-circle-check text-sky-500"></i>
                        <span>{f}</span>
                     </div>
                   ))}
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 hover:bg-sky-600 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95">Buy Now</button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'user_auth' && <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />}
        {currentView === 'profile' && currentUser && <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={handleLogout} />}
        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={handleAdminLogin} onCancel={() => handleNavigate('home')} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && (
          <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={setProducts} onUpdateSettings={setSettings} onUpdateAdmins={setAdmins} onLogout={handleAdminLogout} />
        )}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full shadow-2xl p-8 flex flex-col transition-colors">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black dark:text-white">Review Order</h2>
              <button onClick={() => setIsCartOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-white"><i className="fa-solid fa-xmark text-2xl"></i></button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 pr-2">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50/50 dark:bg-slate-800/50 rounded-xl border border-sky-50 dark:border-slate-800">
                  <img src={item.image} className="w-16 h-16 rounded-lg object-cover" />
                  <div className="flex-1">
                    <p className="font-bold text-slate-800 dark:text-white">{item.name}</p>
                    <p className="text-sky-500 font-bold">₦{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600 transition-colors"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center mt-20 text-slate-400 dark:text-slate-600 space-y-4">
                  <i className="fa-solid fa-cart-shopping text-6xl opacity-20"></i>
                  <p className="font-bold">Cart is empty.</p>
                </div>
              )}
            </div>

            <div className="pt-8 border-t dark:border-slate-800 mt-6">
              <div className="flex justify-between text-2xl font-black mb-6 dark:text-white">
                <span>Total</span>
                <span className="text-sky-500">₦{totalCartPrice.toLocaleString()}</span>
              </div>
              <button 
                onClick={handleCheckout} 
                disabled={isProcessingCheckout || cart.length === 0}
                className="w-full bg-sky-500 hover:bg-sky-600 disabled:bg-sky-300 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center space-x-2"
              >
                {isProcessingCheckout ? (
                  <>
                    <i className="fa-solid fa-spinner animate-spin"></i>
                    <span>Verifying...</span>
                  </>
                ) : (
                  <span>Checkout with Wallet</span>
                )}
              </button>
              {currentUser && <p className="text-center text-xs mt-4 text-slate-400 dark:text-slate-500 font-bold uppercase tracking-widest">WALLET: ₦{currentUser.balance.toLocaleString()}</p>}
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-900 border-t border-sky-100 dark:border-slate-800 py-12 text-center transition-colors">
        <div className="max-w-7xl mx-auto px-4">
          <p className="text-slate-400 dark:text-slate-500 text-xs font-black uppercase tracking-widest">© 2024 NETTOOLZ. All rights reserved.</p>
          <div className="flex justify-center space-x-6 mt-6">
            <span className="text-slate-300 dark:text-slate-600 hover:text-sky-500 cursor-pointer text-[10px] font-black tracking-widest transition-colors">PRIVACY</span>
            <span className="text-slate-300 dark:text-slate-600 hover:text-sky-500 cursor-pointer text-[10px] font-black tracking-widest transition-colors">TERMS</span>
            <span className="text-slate-300 dark:text-slate-600 hover:text-sky-500 cursor-pointer text-[10px] font-black tracking-widest transition-colors">API DOCS</span>
          </div>
          <button onClick={() => handleNavigate('admin_dashboard')} className="mt-8 text-[10px] text-slate-300 dark:text-slate-700 font-black uppercase tracking-[0.2em] hover:text-sky-500 transition-colors">Terminal Portal</button>
        </div>
      </footer>

      <GeminiAssistant />
    </div>
  );
};

export default App;
